INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'c9ed1e65-d898-4fc8-bae3-873678c8e36a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Base EVM Architecture — Understanding Opcodes, Gas Model, and Data Storage$escape$,
  $escape$Base's EVM (Ethereum Virtual Machine) architecture relies on a stack-based execution model, using opcodes to perform operations. The gas model determines the cost of each operation, with gas prices influencing transaction fees. Data is stored in three primary locations: memory (volatile, used for temporary computations), storage (non-volatile, used for contract state), and calldata (immutable, used for function arguments). Understanding these components is crucial for optimizing Base smart contracts. The `base` library provides APIs to interact with the EVM, such as `base.eth.getTransactionCount()` to retrieve the number of transactions sent from a given address.$escape$,
  $escape$console.log(base.eth.getTransactionCount('0x...'))$escape$,
  $escape$javascript$escape$,
